class Solution {
    public String minimizeStringValue(String s) {
        char[] t = s.toCharArray();
        int n = t.length;
        int[] freq = new int[26];
        for (char c : t) if (c != '?') freq[c - 'a']++;

        List<Integer> qPos = new ArrayList<>();
        for (int i = 0; i < n; i++) if (t[i] == '?') qPos.add(i);

        char[] fill = new char[qPos.size()];
        for (int i = 0; i < fill.length; i++) {
            int minChar = 0;
            for (int j = 1; j < 26; j++) if (freq[j] < freq[minChar]) minChar = j;
            fill[i] = (char) (minChar + 'a');
            freq[minChar]++;
        }
        Arrays.sort(fill);

        for (int i = 0; i < qPos.size(); i++) t[qPos.get(i)] = fill[i];
        return new String(t);
    }
}
